import React, { useState, useEffect } from 'react';
import { Menu, X } from 'lucide-react';

const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      isScrolled ? 'bg-white/80 backdrop-blur-md shadow-sm py-3' : 'bg-transparent py-6'
    }`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <div className="flex items-center">
            <span className="text-2xl font-extrabold tracking-tighter text-blue-600">
              STELLARIS <span className="text-slate-900">GOLF</span>
            </span>
          </div>

          <div className="hidden md:flex items-center space-x-8">
            <a href="#problema" className="text-sm font-medium text-slate-600 hover:text-blue-600 transition">El Problema</a>
            <a href="#solucion" className="text-sm font-medium text-slate-600 hover:text-blue-600 transition">Solución</a>
            <a href="#opciones" className="text-sm font-medium text-slate-600 hover:text-blue-600 transition">Opciones</a>
            <a href="#precios" className="text-sm font-medium text-slate-600 hover:text-blue-600 transition">Precios</a>
            <button className="bg-blue-600 text-white px-5 py-2.5 rounded-full text-sm font-semibold hover:bg-blue-700 transition-all transform hover:scale-105 active:scale-95">
              Solicitar Demo
            </button>
          </div>

          <div className="md:hidden">
            <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="text-slate-900">
              {mobileMenuOpen ? <X /> : <Menu />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {mobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 right-0 bg-white border-b border-slate-100 py-4 px-6 flex flex-col space-y-4 shadow-xl animate-in slide-in-from-top-2">
          <a href="#problema" onClick={() => setMobileMenuOpen(false)} className="text-lg font-medium">El Problema</a>
          <a href="#solucion" onClick={() => setMobileMenuOpen(false)} className="text-lg font-medium">Solución</a>
          <a href="#opciones" onClick={() => setMobileMenuOpen(false)} className="text-lg font-medium">Opciones</a>
          <a href="#precios" onClick={() => setMobileMenuOpen(false)} className="text-lg font-medium">Precios</a>
          <button className="bg-blue-600 text-white py-3 rounded-xl font-semibold">
            Solicitar Demo
          </button>
        </div>
      )}
    </nav>
  );
};

