import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Send, Bot, User, Loader2, Sparkles } from 'lucide-react';

const LiveDemo: React.FC = () => {
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant', content: string }[]>([
    { role: 'assistant', content: '¡Hola! Soy el Asistente de Stellaris Golf. Pruébame: pídeme precio para un grupo de 8 jugadores o pregunta por disponibilidad para el próximo fin de semana.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          { role: 'user', parts: [{ text: userMessage }] }
        ],
        config: {
          systemInstruction: `Eres el Asistente Comercial de IA de "Stellaris Golf" para un club de élite. 
          Tu objetivo es demostrar a directores de clubs cómo atiendes a turoperadores.
          - Sé profesional, eficiente y comercial.
          - El club se llama "Stellaris Royal Links".
          - Green Fee estándar: 120€. Turoperadores: 85€.
          - Siempre confirma disponibilidad (invéntala para la demo) y ofrece cerrar la reserva.
          - Si preguntan por grupos de más de 12, ofrece un descuento adicional del 5%.
          - Responde de forma concisa y directa.`,
          temperature: 0.7,
        },
      });

      const aiResponse = response.text || "Lo siento, he tenido un problema técnico. ¿Podrías repetir?";
      setMessages(prev => [...prev, { role: 'assistant', content: aiResponse }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'assistant', content: "Error de conexión. Estoy en modo mantenimiento, pero puedes solicitar una demo real abajo." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section id="demo" className="py-24 bg-white relative">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-16">
          <div className="inline-flex items-center space-x-2 bg-blue-50 text-blue-600 px-4 py-1 rounded-full text-xs font-bold uppercase tracking-widest mb-4">
            <Sparkles className="h-3 w-3" />
            <span>Demo Interactiva Real</span>
          </div>
          <h2 className="text-3xl lg:text-5xl font-extrabold text-slate-900 mb-6">Pruébalo ahora mismo</h2>
          <p className="text-xl text-slate-600 max-w-2xl mx-auto">Interactúa con nuestro asistente comercial y descubre por qué los clubs que lo usan no vuelven a gestionar un email manualmente.</p>
        </div>

        <div className="max-w-4xl mx-auto">
          <div className="bg-slate-900 rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-800 flex flex-col h-[600px]">
            {/* Chat Header */}
            <div className="bg-slate-800/50 p-6 border-b border-slate-700 flex items-center justify-between">
              <div className="flex items-center space-x-3">
                <div className="h-10 w-10 bg-blue-600 rounded-full flex items-center justify-center">
                  <Bot className="text-white h-6 w-6" />
                </div>
                <div>
                  <h3 className="text-white font-bold leading-none">Stellaris Assistant</h3>
                  <p className="text-blue-400 text-xs mt-1 flex items-center">
                    <span className="h-2 w-2 bg-green-500 rounded-full mr-2 animate-pulse"></span>
                    En línea ahora
                  </p>
                </div>
              </div>
              <div className="hidden sm:block">
                <span className="text-slate-500 text-xs font-mono">ID: DEMO-STEL-042</span>
              </div>
            </div>

            {/* Chat Messages */}
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] bg-fixed">
              {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                  <div className={`flex items-start space-x-3 max-w-[85%] ${m.role === 'user' ? 'flex-row-reverse space-x-reverse' : ''}`}>
                    <div className={`h-8 w-8 rounded-full flex-shrink-0 flex items-center justify-center ${m.role === 'user' ? 'bg-slate-700' : 'bg-blue-600'}`}>
                      {m.role === 'user' ? <User className="h-4 w-4 text-white" /> : <Bot className="h-4 w-4 text-white" />}
                    </div>
                    <div className={`p-4 rounded-2xl ${
                      m.role === 'user' 
                        ? 'bg-blue-600 text-white rounded-tr-none' 
                        : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-tl-none'
                    }`}>
                      <p className="text-sm leading-relaxed">{m.content}</p>
                    </div>
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-slate-800 p-4 rounded-2xl rounded-tl-none border border-slate-700 flex items-center space-x-2">
                    <Loader2 className="h-4 w-4 text-blue-400 animate-spin" />
                    <span className="text-slate-400 text-xs italic">Generando propuesta comercial...</span>
                  </div>
                </div>
              )}
            </div>

            {/* Chat Input */}
            <div className="p-6 bg-slate-800/30 border-t border-slate-700">
              <div className="relative">
                <input 
                  type="text" 
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Escribe algo como: 'Necesito 3 salidas para mañana a las 10:00'"
                  className="w-full bg-slate-900 border border-slate-700 rounded-xl py-4 pl-6 pr-14 text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 transition-all shadow-inner"
                />
                <button 
                  onClick={handleSend}
                  disabled={isLoading}
                  className="absolute right-2 top-2 h-10 w-10 bg-blue-600 rounded-lg flex items-center justify-center text-white hover:bg-blue-500 transition-colors disabled:opacity-50"
                >
                  <Send className="h-5 w-5" />
                </button>
              </div>
              <p className="text-[10px] text-slate-500 mt-3 text-center uppercase tracking-widest font-bold">
                Muestra de capacidad de respuesta instantánea
              </p>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default LiveDemo;

import React from 'react';
