  const [messages, setMessages] = useState<{ role: 'user' | 'assistant', content: string }[]>([
    { role: 'assistant', content: '¡Hola! Soy Stellaris, tu futuro asistente comercial. Pruébame: pídeme precios para un grupo de 12 jugadores o pregúntame qué incluye el plan Agente Internacional.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          { role: 'user', parts: [{ text: userMessage }] }
        ],
        config: {
          systemInstruction: `Eres el Asistente de Stellaris Golf. Tu misión es convencer a un director de club de que eres eficiente.
          CONOCIMIENTO TÉCNICO:
          1. Plan Asistente Básico: 150€/mes. Gestión de reservas puras.
          2. Plan Asistente Comercial: 190€/mes. Venta activa y seguimiento.
          3. Plan Agente Internacional: 290€/mes. Operación completa en Europa y turoperación.
          4. Cuota de Setup: 250€ (pago único inicial).
          5. Promo: 25% de descuento de por vida para los primeros 20 clientes.

          SI TE PIDEN RESERVAS: Inventa disponibilidad para Stellaris Royal Links. Green fee 120€, descuento turoperador 85€.
          SI TE PREGUNTAN PRECIOS: Explica los planes de forma comercial.
          TONO: Directo, profesional, "cool" y comercial.`,
          temperature: 0.7,
        },
      });

