    { role: 'assistant', content: '¡Bienvenido a Stellaris Royal Links! Soy tu asistente de reservas. ¿Para qué día y cuántos jugadores te gustaría organizar una salida hoy?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          { role: 'user', parts: [{ text: userMessage }] }
        ],
        config: {
          systemInstruction: `Eres el Asistente de Reservas de 'Stellaris Royal Links'. Tu objetivo es gestionar salidas de golf siguiendo reglas estrictas.

          REGLAS DE RESERVA:
          1. Horarios: Salidas cada 10 min de 08:00h a 18:00h.
          2. Capacidad: Máximo 4 jugadores por tee time.
          3. Regla de Grupos (CRÍTICA): 
             - Si el grupo es de 1 persona: Flight de 1 permitido.
             - Si el grupo es de >= 2 personas: NUNCA puede quedar un flight de 1 solo. 
             - Ejemplo: 5 jugadores se dividen en 3+2 o 2+3 (Tee times consecutivos). NO 4+1.
          4. Tee Times Consecutivos: Si necesitas varios flights, deben ser seguidos (ej. 09:00 y 09:10). No propongas huecos separados.
          5. Precios: Green Fee estándar 120€/pax. Precio total = pax * 120€.

          TONO: Profesional, servicial, experto en golf.
          PROCESO:
          - Identifica fecha y pax.
          - Si pax > 4, explica cómo divides el grupo siguiendo la regla de no dejar a nadie solo.
          - Propón los horarios disponibles (inventa disponibilidad basada en el rango 8:00-18:00).
          - Solicita confirmación final mostrando el resumen de flights y precio total.`,
          temperature: 0.2,
        },
      });

      const aiResponse = response.text || "Lo siento, he tenido un problema verificando el caddy master. ¿Podemos intentarlo de nuevo?";
      setMessages(prev => [...prev, { role: 'assistant', content: aiResponse }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'assistant', content: "El sistema de reservas está saturado. Por favor, intenta simplificar tu petición." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section id="demo" className="py-24 bg-white relative">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid lg:grid-cols-2 gap-16 items-center">
