                <div className="flex justify-start">
                  <div className="bg-slate-800 p-4 rounded-2xl rounded-tl-none border border-slate-700 flex items-center space-x-2">
                    <Loader2 className="h-4 w-4 text-blue-400 animate-spin" />
                    <span className="text-[10px] text-slate-500 font-bold uppercase">Consultando disponibilidad...</span>
                  </div>
                </div>
              )}
            </div>

            <div className="p-6 bg-slate-800/30 border-t border-slate-700">
              <div className="relative">
                <input 
                  type="text" 
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Ej: Salida para 4 mañana a las 10:00..."
                  className="w-full bg-slate-900 border border-slate-700 rounded-xl py-4 pl-6 pr-14 text-white placeholder-slate-500 focus:outline-none focus:border-blue-500 transition-all"
