import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Send, Bot, Loader2, Sparkles, Calendar, Users, Clock } from 'lucide-react';

const LiveDemo: React.FC = () => {
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant', content: string }[]>([
    { role: 'assistant', content: 'Hola. Soy Stellaris. ¿Fecha y número de jugadores para tu reserva?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          { role: 'user', parts: [{ text: userMessage }] }
        ],
        config: {
          systemInstruction: `Eres Stellaris, un asistente de reservas de golf ultra-eficiente. 
          TU ESTILO: Respuestas cortas, directas y profesionales. No saludes dos veces. Ve al grano.

          REGLAS DE NEGOCIO (ESTRICTAS):
          1. Horarios: 08:00h a 18:00h cada 10 min.
          2. Flights: Máx 4 pax. 
          3. Regla de "Nadie Solo": Si total pax >= 2, no puede haber un flight de 1.
             - Ej 5 pax: Se dividen en 3+2 o 2+3. NO 4+1.
          4. Consecutivos: Flights deben ser en horas contiguas (ej. 09:00 y 09:10).
          5. Precio: 120€/pax.

          FORMATO DE RESPUESTA:
          - Confirmación de disponibilidad.
          - Desglose de flights (pax por salida).
          - Horarios propuestos.
          - Precio total.
          - Pregunta final mínima (¿Confirmas?).`,
          temperature: 0.1,
        },
      });

      const aiResponse = response.text || "Error de conexión. Inténtalo de nuevo.";
      setMessages(prev => [...prev, { role: 'assistant', content: aiResponse }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'assistant', content: "Sistema ocupado. Por favor, sé más específico." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section id="demo" className="py-24 bg-white relative">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid lg:grid-cols-2 gap-16 items-center">
          <div>
            <div className="inline-flex items-center space-x-2 bg-blue-50 text-blue-600 px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-widest mb-6">
              <Sparkles className="h-3 w-3" />
              <span>Gestión de Reservas IA</span>
            </div>
            <h2 className="text-4xl lg:text-5xl font-extrabold text-slate-900 mb-6 leading-tight">
              Precisión en <br/><span className="text-blue-600 text-gradient">Tiempo Real</span>
            </h2>
            <p className="text-lg text-slate-600 mb-8 leading-relaxed font-light">
              Nuestra IA no divaga. Aplica reglas de flight, evita que nadie juegue solo y bloquea horarios consecutivos de forma automática.
            </p>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
              <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center space-x-3">
                <Clock className="h-5 w-5 text-blue-500" />
                <span className="text-sm font-medium text-slate-700">Intervalos de 10 min</span>
              </div>
              <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center space-x-3">
                <Users className="h-5 w-5 text-blue-500" />
                <span className="text-sm font-medium text-slate-700">División inteligente de flights</span>
              </div>
            </div>

            <div className="bg-blue-50 p-6 rounded-3xl border border-blue-100 text-blue-800 text-sm font-medium">
              "Prueba: 'Reserva para 5 mañana a las 9'. Mira cómo resuelve los flights automáticamente."
            </div>
          </div>

          <div className="bg-slate-900 rounded-[3rem] shadow-2xl overflow-hidden border border-slate-800 flex flex-col h-[550px] relative">
            <div className="bg-slate-800/80 p-5 border-b border-slate-700 flex items-center justify-between backdrop-blur-md">
              <div className="flex items-center space-x-3">
                <div className="h-8 w-8 bg-blue-600 rounded-full flex items-center justify-center">
                  <Bot className="text-white h-5 w-5" />
                </div>
                <div>
                  <h3 className="text-white text-sm font-bold leading-none">Asistente Stellaris</h3>
                  <p className="text-blue-400 text-[9px] mt-1 uppercase font-bold tracking-widest">Respuesta instantánea</p>
                </div>
              </div>
            </div>

            <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]">
              {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-1`}>
                  <div className={`p-4 rounded-2xl max-w-[90%] shadow-lg ${
